import { useState, useEffect, useCallback, useRef } from "react";

const GRID = 3;
const SOLVED = Array.from({ length: GRID * GRID }, (_, i) => i);

const NFT_IMAGES = [
  { id: 1, label: "Bear Hunter", tag: "#0001", url: `data:image/jpeg;base64,` },
  { id: 2, label: "Blade Racer", tag: "#0042", url: `data:image/jpeg;base64,` },
  { id: 3, label: "Dark Elf",    tag: "#0099", url: `data:image/jpeg;base64,` },
  { id: 4, label: "Momo Store",  tag: "#0137", url: `data:image/jpeg;base64,` },
];

function isSolvable(tiles) {
  const arr = tiles.filter(t => t !== 0);
  let inv = 0;
  for (let i = 0; i < arr.length - 1; i++)
    for (let j = i + 1; j < arr.length; j++)
      if (arr[i] > arr[j]) inv++;
  return inv % 2 === 0;
}

function shuffle() {
  let arr;
  do { arr = [...SOLVED].sort(() => Math.random() - 0.5); }
  while (!isSolvable(arr) || arr.join() === SOLVED.join());
  return arr;
}

function isSolved(tiles) { return tiles.join() === SOLVED.join(); }

// ─── Responsive hook ───────────────────────────────────────────────────────
function useWindowSize() {
  const [size, setSize] = useState({ w: window.innerWidth, h: window.innerHeight });
  useEffect(() => {
    const handler = () => setSize({ w: window.innerWidth, h: window.innerHeight });
    window.addEventListener("resize", handler);
    return () => window.removeEventListener("resize", handler);
  }, []);
  return size;
}


